import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import { Plus, Check, X, Search, MoreVertical } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

const VendorList = () => {
  const [vendors, setVendors] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const { user } = useAuth();

  useEffect(() => {
    fetchVendors();
  }, []);

  const fetchVendors = async () => {
    try {
      const response = await axios.get('http://10.113.178.31:8080/api/vendors');
      setVendors(response.data);
    } catch (err) {
      console.error('Error fetching vendors', err);
    } finally {
      setLoading(false);
    }
  };

  const handleStatusUpdate = async (id, action) => {
    try {
      await axios.put(`http://10.113.178.31:8080/api/vendors/${id}/${action}`);
      fetchVendors();
    } catch (err) {
      alert('Failed to update status: ' + err.message);
    }
  };

  const filteredVendors = vendors.filter(v => 
    v.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    v.vendorId.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-800">Street Vendors</h1>
          <p className="text-gray-500 text-sm">Manage and monitor all registered vendors in Solapur</p>
        </div>
        {user.role === 'ADMIN' && (
          <Link to="/vendors/add" className="bg-smc-blue text-white px-4 py-2 rounded-lg font-semibold flex items-center gap-2 hover:bg-blue-800 transition shadow-md">
            <Plus size={18} /> Register Vendor
          </Link>
        )}
      </div>

      <div className="bg-white rounded-xl shadow-md overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50 flex items-center gap-2">
          <Search size={18} className="text-gray-400" />
          <input 
            type="text" 
            placeholder="Search by name or Vendor ID..." 
            className="bg-transparent border-none outline-none text-sm w-full"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 text-gray-500 text-xs uppercase tracking-wider">
              <tr>
                <th className="px-6 py-3 font-semibold">Vendor Info</th>
                <th className="px-6 py-3 font-semibold">Category</th>
                <th className="px-6 py-3 font-semibold">Location</th>
                <th className="px-6 py-3 font-semibold">Status</th>
                <th className="px-6 py-3 font-semibold">QR Code</th>
                <th className="px-6 py-3 font-semibold">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {loading ? (
                <tr><td colSpan="6" className="text-center py-8">Loading vendors...</td></tr>
              ) : filteredVendors.length === 0 ? (
                <tr><td colSpan="6" className="text-center py-8">No vendors found</td></tr>
              ) : (
                filteredVendors.map(vendor => (
                  <tr key={vendor.id} className="hover:bg-gray-50 transition">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center text-smc-blue font-bold">
                          {vendor.name.charAt(0)}
                        </div>
                        <div>
                          <p className="font-semibold text-gray-800">{vendor.name}</p>
                          <p className="text-xs text-gray-500">{vendor.vendorId}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-full uppercase">
                        {vendor.category}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      <p className="truncate max-w-[150px]">{vendor.address || 'N/A'}</p>
                      <p className="text-[10px] text-gray-400">{vendor.latitude.toFixed(4)}, {vendor.longitude.toFixed(4)}</p>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`text-xs px-2 py-1 rounded-full font-semibold ${
                        vendor.status === 'APPROVED' ? 'bg-green-100 text-green-700' :
                        vendor.status === 'PENDING' ? 'bg-yellow-100 text-yellow-700' :
                        'bg-red-100 text-red-700'
                      }`}>
                        {vendor.status}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      {vendor.qrCodeUrl ? (
                        <a href={`http://10.113.178.31:8080${vendor.qrCodeUrl}`} target="_blank" rel="noreferrer" className="text-smc-blue hover:underline flex items-center gap-1">
                          <Check size={14} /> View
                        </a>
                      ) : (
                        <span className="text-gray-400 text-xs italic">Not Generated</span>
                      )}
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex gap-2">
                        {user.role === 'ADMIN' && vendor.status === 'PENDING' && (
                          <>
                            <button onClick={() => handleStatusUpdate(vendor.id, 'approve')} className="p-1 text-green-600 hover:bg-green-50 rounded" title="Approve">
                              <Check size={18} />
                            </button>
                            <button onClick={() => handleStatusUpdate(vendor.id, 'reject')} className="p-1 text-red-600 hover:bg-red-50 rounded" title="Reject">
                              <X size={18} />
                            </button>
                          </>
                        )}
                        <button className="p-1 text-gray-400 hover:bg-gray-100 rounded">
                          <MoreVertical size={18} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default VendorList;
